import React from "react";
import MealCard from "../Components/MealCard";

const MealPlan = () => {
  // Retrieve patient data
  const patientData = JSON.parse(localStorage.getItem("patientData")) || {};

  // Generate sample meals based on goal (simple example)
  const meals = [
    {
      mealType: "Breakfast",
      mealName:
        patientData.goal === "weight-loss"
          ? "Oatmeal with berries"
          : "Pancakes with banana",
      calories: patientData.goal === "weight-loss" ? 300 : 450,
      protein: 10,
      carbs: 50,
      bgColor: "#ffe0b2",
    },
    {
      mealType: "Lunch",
      mealName:
        patientData.goal === "weight-loss"
          ? "Grilled chicken salad"
          : "Chicken sandwich with veggies",
      calories: patientData.goal === "weight-loss" ? 400 : 600,
      protein: 35,
      carbs: 45,
      bgColor: "#c8e6c9",
    },
    {
      mealType: "Dinner",
      mealName:
        patientData.goal === "weight-loss"
          ? "Steamed fish with vegetables"
          : "Pasta with chicken",
      calories: patientData.goal === "weight-loss" ? 350 : 550,
      protein: 30,
      carbs: 60,
      bgColor: "#bbdefb",
    },
  ];

  return (
    <div className="container my-5">
      <h2 className="text-center mb-4">
        Meal Plan for {patientData.patientName || "Patient"}
      </h2>
      <div className="row g-4">
        {meals.map((meal) => (
          <div className="col-md-4" key={meal.mealType}>
            <MealCard {...meal} />
          </div>
        ))}
      </div>
    </div>
  );
};

export default MealPlan;
